import { Col, Row } from "antd"
import dayjs from "dayjs"
import isBetween from "dayjs/plugin/isBetween"
import moment from "moment"
import { useEffect, useMemo, useState } from "react"
import { useSelector } from "react-redux"
import DatePickerCustom from "src/components/Date/DatePickerCustom"
import { FloatActionWrapper } from "src/components/FloatAction/styles"
import InputCustom from "src/components/Input/InputCustom"
import CB1 from "src/components/Modal/CB1"
import ButtonCustom from "src/components/MyButton/Button"
import ButtonCircle from "src/components/MyButton/ButtonCircle"
import notice from "src/components/Notice"
import SelectCustom from "src/components/Select/SelectCustom"
import SpinCustom from "src/components/SpinCustom"
import TableCustom from "src/components/Table/CustomTable"
import {
  MainTableData,
  SubTableData,
} from "src/components/Table/CustomTable/styled"
import TitleCustom from "src/components/TitleCustom"
import { hideOnSinglePage, SYSTEM_KEY } from "src/constants/constants"
import { useBadgeCounts } from "src/hooks/useBadgeCounts"
import { getListComboByKey, getSystemKeyDescription } from "src/lib/utils"
import MemberService from "src/services/MemberService"
import "./style.scss"
dayjs.extend(isBetween)

const ApprovalJoin = () => {
  const [loading, setLoading] = useState(false)
  const [detailModalOpen, setDetailModalOpen] = useState(false)
  const [selectedRequest, setSelectedRequest] = useState(null)
  const [listData, setListData] = useState([])
  const [pagination, setPagination] = useState({ pageSize: 20, currentPage: 1 })
  const [selectedRowKeys, setSelectedRowKeys] = useState([])
  const [status, setStatus] = useState("all")
  const [requestStatus, setRequestStatus] = useState("1")
  const [textSearchCCCD, setTextSearchCCCD] = useState("")
  const [textSearchMST, setTextSearchMST] = useState("")
  const { listSystemKey } = useSelector(state => state.appGlobal)
  const [dateFilter, setDateFilter] = useState([])

  // Use useBadgeCounts hook for real-time badge updates
  const { badgeCounts } = useBadgeCounts()

  // const memberTypeOptions = useMemo(() => {
  //   const raw = getListComboByKey(SYSTEM_KEY.MEMBER_TYPE, listSystemKey) || []
  //   return [
  //     { CodeKey: "all", CodeValue: "all", Description: "Tất cả" },
  //     ...raw.map(item => ({
  //       ...item,
  //       CodeValue: Number(item.CodeValue),
  //     })),
  //   ]
  // }, [listSystemKey])

  const requestStatusOptions = useMemo(() => {
    const list = getListComboByKey(SYSTEM_KEY.USER_STATUS, listSystemKey)
    return list || []
  }, [listSystemKey])

  const pendingRequestsCount = badgeCounts.joinRequest || 0

  useEffect(() => {
    fetchList()
  }, [
    pagination.currentPage,
    pagination.pageSize,
    status,
    requestStatus,
    textSearchCCCD,
    textSearchMST,
    dateFilter,
  ])

  const fetchList = async () => {
    try {
      setLoading(true)
      const params = {
        PageSize: pagination.pageSize,
        CurrentPage: pagination.currentPage,
        MemberType: status !== "all" ? Number(status) : undefined,
        Status: requestStatus !== "all" ? Number(requestStatus) : undefined,
        TextSearch: textSearchCCCD || undefined,
        TaxCodeSearch: textSearchMST || undefined,
      }

      if (Array.isArray(dateFilter) && dateFilter.length === 2) {
        params.FromDate = dayjs(dateFilter[0]).format("YYYY/MM/DD")
        params.ToDate = dayjs(dateFilter[1]).add(1, "day").format("YYYY/MM/DD")
      }

      const res = await MemberService.getListJoinRequest(params)
      if (res?.isError) return

      setListData({
        ListUserRequest: res?.Object?.ListUserRequest || [],
        Total: res?.Object?.Total ?? 0,
      })
    } catch (error) {
      console.error("fetchList error:", error)
    } finally {
      setLoading(false)
    }
  }

  const approveRequests = async IDs => {
    try {
      setLoading(true)
      const res = await MemberService.approveJoinRequest(IDs)
      if (res?.isOk) {
        notice({ msg: "Duyệt thành công!" })
        return true
      }
    } catch (error) {
      notice({ msg: "Có lỗi xảy ra khi duyệt!", isSuccess: false })
      return false
    } finally {
      setLoading(false)
    }
  }

  const rejectRequests = async IDs => {
    try {
      setLoading(true)
      const res = await MemberService.rejectJoinRequest(IDs)
      if (res?.isOk) {
        notice({ msg: "Từ chối thành công!" })
        return true
      }
    } catch (error) {
      notice({ msg: "Có lỗi xảy ra khi từ chối!", isSuccess: false })
      return false
    } finally {
      setLoading(false)
    }
  }

  const handleBulkApprove = () => {
    if (selectedRowKeys.length === 0) {
      notice({
        msg: "Vui lòng chọn ít nhất một yêu cầu để chấp nhận.",
        isSuccess: false,
      })
      return
    }

    const selectedRecords = listData.ListUserRequest.filter(
      item => selectedRowKeys.includes(item.ID) && item.ButtonShow?.IsApprove,
    )

    CB1({
      title: `Bạn có chắc chắn muốn duyệt ${selectedRecords.length} yêu cầu?`,
      icon: "check-circle",
      okText: "Đồng ý",
      onOk: async close => {
        const ids = selectedRecords.map(item => item.ID)
        const success = await approveRequests(ids)
        if (success) {
          await fetchList()
          setSelectedRowKeys([])
          close()
        }
      },
    })
  }

  const handleBulkReject = () => {
    if (selectedRowKeys.length === 0) {
      notice({
        msg: "Vui lòng chọn ít nhất một yêu cầu để từ chối.",
        isSuccess: false,
      })
      return
    }

    const selectedRecords = listData.ListUserRequest.filter(
      item =>
        selectedRowKeys.includes(item.UserID) && item.ButtonShow?.IsReject,
    )

    CB1({
      title: `Bạn có chắc chắn muốn từ chối ${selectedRecords.length} yêu cầu?`,
      icon: "cancel",
      okText: "Đồng ý",
      onOk: async close => {
        const ids = selectedRecords.map(item => item.ID)
        const success = await rejectRequests(ids)
        if (success) {
          await fetchList()
          setSelectedRowKeys([])
          close()
        }
      },
    })
  }

  const handleViewDetail = record => {
    setSelectedRequest({
      memberId: record.UserID,
      memberType: record.MemberType === "Cá nhân" ? 1 : 2,
    })
    setDetailModalOpen(true)
  }

  const handleDateFilterChange = dates => {
    setDateFilter(dates && dates.length === 2 ? dates : [])
    setPagination(prev => ({ ...prev, currentPage: 1 }))
  }
  const getStatusName = value =>
    getSystemKeyDescription(SYSTEM_KEY?.USER_STATUS, value, listSystemKey)

  const columns = [
    {
      title: "STT",
      dataIndex: "index",
      key: "index",
      width: 70,
      align: "center",
      render: (val, record, idx) => (
        <div className="text-center">
          {idx + 1 + pagination.pageSize * (pagination.currentPage - 1)}
        </div>
      ),
    },
    {
      title: (
        <div>
          <MainTableData>Số CCCD/MST</MainTableData>
          <SubTableData style={{ color: "white" }}>Loại</SubTableData>
        </div>
      ),
      dataIndex: "Identity",
      key: "Identity",
      align: "center",
      render: (text, record) => (
        <div onMouseDown={e => e.stopPropagation()}>
          <MainTableData>{text || "-"}</MainTableData>
          <SubTableData className="fs-13">
            {record?.MemberType || "-"}
          </SubTableData>
        </div>
      ),
    },
    {
      title: (
        <div>
          <MainTableData>Tên</MainTableData>
          <SubTableData style={{ color: "white" }}>Loại tài khoản</SubTableData>
        </div>
      ),
      key: "PackageName",
      align: "center",
      render: (value, record) => (
        <div onMouseDown={e => e.stopPropagation()}>
          <MainTableData className="max-line1">
            {record?.FullName || "-"}
          </MainTableData>
          <SubTableData className="fs-13">
            {record?.PackageName || "-"}
          </SubTableData>
        </div>
      ),
    },
    {
      title: "Ngày làm đơn",
      dataIndex: "CreateDate",
      key: "CreateDate",
      align: "center",
      render: text => text && moment(text).format("DD/MM/YYYY"),
    },
    {
      title: "Hội nhóm",
      dataIndex: "AssociationName",
      key: "AssociationName",
      align: "center",
      render: (text, record) => (
        <MainTableData className="max-line1">
          {record?.AssociationName || "-"}
        </MainTableData>
      ),
    },
    {
      title: (
        <div>
          <MainTableData>Số điện thoại</MainTableData>
          <SubTableData style={{ color: "white" }}>Email</SubTableData>
        </div>
      ),
      key: "PhoneEmail",
      align: "center",
      render: (value, record) => (
        <div onMouseDown={e => e.stopPropagation()}>
          <MainTableData className="max-line1">
            {record?.PhoneNumber || "-"}
          </MainTableData>
          <SubTableData className="fs-13">{record?.Email || "-"}</SubTableData>
        </div>
      ),
    },
    {
      title: "Trạng thái",
      dataIndex: "Status",
      key: "StatusAction",
      align: "center",
      render: (isStatus, record) => {
        const statusName = getStatusName(isStatus)
        const isActive = isStatus === 1
        let statusStyle = {}

        if (statusName === "Chờ duyệt") {
          statusStyle = { color: "#FF8C00", fontWeight: "bold" }
        } else if (statusName === "Đã duyệt") {
          statusStyle = { color: "#008000", fontWeight: "bold" }
        } else if (statusName === "Từ chối") {
          statusStyle = { color: "#FF0000", fontWeight: "bold" }
        }

        return (
          <div className="text-center">
            <div className="max-line2" title={statusName} style={statusStyle}>
              {statusName}
            </div>

            {(record?.ButtonShow?.IsApprove ||
              record?.ButtonShow?.IsReject) && (
              <FloatActionWrapper
                size="small"
                className="float-action__wrapper"
              >
                {record.ButtonShow.IsApprove && (
                  <ButtonCircle
                    className="button-circle"
                    title="Chấp nhận"
                    iconName="check-circle"
                    style={{
                      background: "#EDF6FC",
                      boxShadow: "0px 2px 4px rgba(208, 206, 187, 0.5)",
                    }}
                    onClick={e => {
                      e.stopPropagation()
                      CB1({
                        title: "Bạn có chắc chắn muốn duyệt không?",
                        icon: "check-circle",
                        okText: "Đồng ý",
                        onOk: async close => {
                          const success = await approveRequests([record.ID])
                          if (success) {
                            await fetchList()
                          }
                          close()
                        },
                      })
                    }}
                  />
                )}

                {record.ButtonShow.IsReject && (
                  <ButtonCircle
                    className="button-circle"
                    title="Từ chối"
                    iconName="cancel"
                    style={{
                      background: "#FFE9EC",
                      boxShadow: "0px 2px 4px rgba(208, 206, 187, 0.5)",
                    }}
                    onClick={e => {
                      e.stopPropagation()
                      CB1({
                        title: "Bạn có chắc chắn muốn từ chối không?",
                        icon: "cancel",
                        okText: "Đồng ý",
                        onOk: async close => {
                          const success = await rejectRequests([record.ID])
                          if (success) {
                            await fetchList()
                          }
                          close()
                        },
                      })
                    }}
                  />
                )}
              </FloatActionWrapper>
            )}
          </div>
        )
      },
    },
  ]

  return (
    <SpinCustom spinning={loading}>
      <Row
        className="box-action sticky"
        gutter={12}
        style={{ marginBottom: 16 }}
      >
        <Col span={24}>
          <TitleCustom className={"d-flex-sb"}>
            {
              <div
                style={{
                  position: "relative",
                  display: "flex",
                }}
              >
                <span>Danh sách duyệt gia nhập ({pendingRequestsCount})</span>
              </div>
            }
            <div className="d-flex-end">
              <ButtonCustom
                type="primary"
                className="btn-hover-shadow mr-8"
                onClick={handleBulkApprove}
              >
                Chấp nhận
              </ButtonCustom>
              <ButtonCustom
                type="primary"
                className="btn-hover-shadow"
                onClick={handleBulkReject}
              >
                Từ chối
              </ButtonCustom>
            </div>
          </TitleCustom>
        </Col>
        <Col span={12}>
          <InputCustom
            type="search"
            allowClear
            label="Tìm theo CCCD"
            enterButton
            onChange={val => {
              setTextSearchCCCD(val.target.value)
              setPagination(prev => ({ ...prev, currentPage: 1 }))
            }}
          />
        </Col>

        {/* <Col span={6}>
          <InputCustom
            type="search"
            allowClear
            label="Tìm theo Mã số thuế"
            enterButton
            onChange={val => {
              setTextSearchMST(val.target.value)
              setPagination(prev => ({ ...prev, currentPage: 1 }))
            }}
          />
        </Col> */}

        <Col span={6}>
          <DatePickerCustom
            type={"ranger"}
            style={{ width: "100%" }}
            format="DD/MM/YYYY"
            allowClear
            value={dateFilter}
            onChange={handleDateFilterChange}
            placeholder={["Từ ngày", "Đến ngày"]}
          />
        </Col>
        {/* <Col span={3}>
          <SelectCustom
            allowClear
            style={{ width: "100%" }}
            onChange={value => setStatus(value || "all")}
            value={status}
            maxTagCount="responsive"
            label="Trạng thái"
          >
            {memberTypeOptions.map(item => (
              <Select.Option key={item.CodeKey} value={item.CodeValue}>
                {item.Description}
              </Select.Option>
            ))}
          </SelectCustom>
        </Col> */}
        <Col span={6}>
          <SelectCustom
            allowClear
            style={{ width: "100%" }}
            onChange={value => setRequestStatus(value)}
            value={
              requestStatusOptions?.find(
                item => item.CodeValue === requestStatus,
              )?.CodeValue
            }
            label="Trạng thái "
          >
            {requestStatusOptions
              ?.filter(item => item.CodeKey !== "USER_STATUS")
              ?.map(item => (
                <SelectCustom.Option key={item.CodeKey} value={item.CodeValue}>
                  {item.Description}
                </SelectCustom.Option>
              ))}
          </SelectCustom>
        </Col>
      </Row>

      <TableCustom
        sticky={{ offsetHeader: -12 }}
        columns={columns}
        dataSource={listData.ListUserRequest}
        textEmpty="Không có dữ liệu"
        rowKey="ID"
        rowSelection={{
          selectedRowKeys,
          onChange: keys => setSelectedRowKeys(keys),
          getCheckboxProps: record => ({
            disabled: !(
              record.ButtonShow?.IsApprove || record.ButtonShow?.IsReject
            ),
          }),
        }}
        pagination={{
          hideOnSinglePage: listData.Total <= hideOnSinglePage,
          current: pagination.currentPage,
          pageSize: pagination.pageSize,
          responsive: true,
          total: listData.Total,
          locale: { items_per_page: "" },
          showSizeChanger: listData.Total > 10,
          onChange: (currentPage, pageSize) => {
            setPagination(prev => ({
              ...prev,
              currentPage,
              pageSize,
            }))
          },
        }}
        onRow={record => ({
          onClick: () => {
            if (
              window.getSelection().toString() ||
              !record.ButtonShow?.IsDetail
            )
              return
            handleViewDetail(record)
          },
        })}
      />

      {/* <MemberDetailModal
        open={detailModalOpen}
        selectedRequest={selectedRequest}
        onCancel={() => setDetailModalOpen(false)}
        onOk={() => fetchList()}
      /> */}
    </SpinCustom>
  )
}

export default ApprovalJoin
